40вҶ’/** @internal Log a non-fatal warning: one-line summary always, detail in verbose. */
41вҶ’export function logNonFatalWarning(
42вҶ’  message: string,
43вҶ’  error: unknown,
44вҶ’  verbose: boolean,
45вҶ’): void {
46вҶ’  console.log(chalk.yellow(message));
47вҶ’  if (verbose) {
48вҶ’    console.log(chalk.gray(`    ${error}`));
49вҶ’  }
50вҶ’}

  1вҶ’/**
  2вҶ’ * Assess Comment Parser
  3вҶ’ *
  4вҶ’ * Detects and parses /assess command output from GitHub issue comments.
  5вҶ’ * This is the unified parser that handles both the new /assess format
  6вҶ’ * and the legacy /solve format for backward compatibility.
  7вҶ’ *
  8вҶ’ * When an assess comment exists, its phase recommendations take precedence
  9вҶ’ * over content analysis (but not over labels).
 10вҶ’ *
 11вҶ’ * @example
 12вҶ’ * ```typescript
 13вҶ’ * import { findAssessComment, parseAssessWorkflow } from './assess-comment-parser';
 14вҶ’ *
 15вҶ’ * const comments = [
 16вҶ’ *   { body: "Some regular comment" },
 17вҶ’ *   { body: "## Assess Analysis\n\nвҶ’ PROCEED вҖ” Ready.\n\n<!-- assess:phases=spec,exec,qa -->" },
 18вҶ’ * ];
 19вҶ’ *
 20вҶ’ * const assessComment = findAssessComment(comments);
 21вҶ’ * if (assessComment) {
 22вҶ’ *   const workflow = parseAssessWorkflow(assessComment.body);
 23вҶ’ *   // workflow: { phases: ['spec', 'exec', 'qa'], action: 'PROCEED', ... }
 24вҶ’ * }
 25вҶ’ * ```
 26вҶ’ */
 27вҶ’
 28вҶ’import type { Phase } from "./workflow/types.js";
 29вҶ’import type { PhaseSignal } from "./phase-signal.js";
 30вҶ’
 31вҶ’/**
 32вҶ’ * The 6 fixed actions that /assess can recommend
 33вҶ’ */
 34вҶ’export type AssessAction =
 35вҶ’  | "PROCEED"
 36вҶ’  | "CLOSE"
 37вҶ’  | "MERGE"
 38вҶ’  | "REWRITE"
 39вҶ’  | "CLARIFY"
 40вҶ’  | "PARK";
 41вҶ’
 42вҶ’/**
 43вҶ’ * Result of parsing an assess comment (superset of SolveWorkflowResult)
 44вҶ’ */
 45вҶ’export interface AssessWorkflowResult {
 46вҶ’  /** Phases recommended by assess (only meaningful for PROCEED) */
 47вҶ’  phases: Phase[];
 48вҶ’  /** Whether quality loop is recommended */
 49вҶ’  qualityLoop: boolean;
 50вҶ’  /** The issue numbers mentioned in the assess comment */
 51вҶ’  issueNumbers: number[];
 52вҶ’  /** Raw workflow string (e.g., "spec вҶ’ exec вҶ’ qa") */
 53вҶ’  workflowString?: string;
 54вҶ’  /** The recommended action (one of the 6 fixed actions) */
 55вҶ’  action?: AssessAction;
 56вҶ’}
 57вҶ’
 58вҶ’/**
 59вҶ’ * Backward-compatible alias for AssessWorkflowResult
 60вҶ’ */
 61вҶ’export type SolveWorkflowResult = AssessWorkflowResult;
 62вҶ’
 63вҶ’/**
 64вҶ’ * Comment structure (simplified from GitHub API)
 65вҶ’ */
 66вҶ’export interface IssueComment {
 67вҶ’  body: string;
 68вҶ’  author?: {
 69вҶ’    login: string;
 70вҶ’  };
 71вҶ’  createdAt?: string;
 72вҶ’}
 73вҶ’
 74вҶ’/**
 75вҶ’ * Markers that indicate an assess comment (new format)
 76вҶ’ */
 77вҶ’const ASSESS_MARKERS = [
 78вҶ’  "## Assess Analysis",
 79вҶ’  "## Assess Workflow",
 80вҶ’  "*Generated by `/assess",
 81вҶ’];
 82вҶ’
 83вҶ’/**
 84вҶ’ * Markers that indicate a solve comment (legacy format)
 85вҶ’ */
 86вҶ’const SOLVE_MARKERS = [
 87вҶ’  "## Solve Analysis",
 88вҶ’  "## Solve Workflow for Issues:",
 89вҶ’  "## Solve Workflow for Issue:",
 90вҶ’  "### Recommended Workflow",
 91вҶ’  "*рҹ“қ Generated by `/solve",
 92вҶ’];
 93вҶ’
 94вҶ’/**
 95вҶ’ * All markers (both assess and solve)
 96вҶ’ */
 97вҶ’const ALL_MARKERS = [...ASSESS_MARKERS, ...SOLVE_MARKERS];
 98вҶ’
 99вҶ’/**
100вҶ’ * Pattern to extract phases from workflow string
101вҶ’ * Matches: `/spec`, `/exec`, `/test`, `/qa`, etc.
102вҶ’ * Also matches without slash: `spec`, `exec`, `test`, `qa` (for arrow notation)
103вҶ’ */
104вҶ’const PHASE_PATTERN =
105вҶ’  /\/?(?<!\w)(spec|exec|test|qa|security-review|testgen|loop)(?!\w)/g;
106вҶ’
107вҶ’/**
108вҶ’ * Pattern to detect quality loop recommendation
109вҶ’ */
110вҶ’const QUALITY_LOOP_PATTERNS = [
111вҶ’  /quality\s*loop.*auto-enable/i,
112вҶ’  /--quality-loop/i,
113вҶ’  /quality\s*loop.*recommended/i,
114вҶ’  /enable.*quality\s*loop/i,
115вҶ’];
116вҶ’
117вҶ’/**
118вҶ’ * Pattern to extract structured data from HTML comment markers
119вҶ’ * Matches both: <!-- assess:phases=exec,qa --> and <!-- solve:phases=exec,qa -->
120вҶ’ */
121вҶ’const HTML_MARKER_PATTERN =
122вҶ’  /<!--\s*(?:assess|solve):(\w[\w-]*)=([\w,.-]*)\s*-->/g;
123вҶ’
124вҶ’/**
125вҶ’ * Pattern to extract assess-specific HTML markers (takes precedence)
126вҶ’ */
127вҶ’const ASSESS_HTML_MARKER_PATTERN = /<!--\s*assess:(\w[\w-]*)=([\w,.-]*)\s*-->/g;
128вҶ’
129вҶ’/**
130вҶ’ * Pattern to extract issue numbers from header
131вҶ’ * Matches: "## Solve Workflow for Issues: 123, 456" or "#123"
132вҶ’ */
133вҶ’const ISSUE_NUMBER_PATTERN = /#?(\d+)/g;
134вҶ’
135вҶ’/**
136вҶ’ * Valid assess actions
137вҶ’ */
138вҶ’const VALID_ACTIONS: AssessAction[] = [
139вҶ’  "PROCEED",
140вҶ’  "CLOSE",
141вҶ’  "MERGE",
142вҶ’  "REWRITE",
143вҶ’  "CLARIFY",
144вҶ’  "PARK",
145вҶ’];
146вҶ’
147вҶ’/**
148вҶ’ * Structured data extracted from HTML comment markers
149вҶ’ */
150вҶ’export interface AssessMarkers {
151вҶ’  /** Recommended phases */
152вҶ’  phases?: string[];
153вҶ’  /** Whether to skip spec */
154вҶ’  skipSpec?: boolean;
155вҶ’  /** Whether browser testing is needed */
156вҶ’  browserTest?: boolean;
157вҶ’  /** Whether quality loop is recommended */
158вҶ’  qualityLoop?: boolean;
159вҶ’  /** The recommended action */
160вҶ’  action?: AssessAction;
161вҶ’}
162вҶ’
163вҶ’/**
164вҶ’ * Backward-compatible alias for AssessMarkers
165вҶ’ */
166вҶ’export type SolveMarkers = AssessMarkers;
167вҶ’
168вҶ’// в”Җв”Җв”Җ Detection Functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
169вҶ’
170вҶ’/**
171вҶ’ * Check if a comment is an assess command output (new format)
172вҶ’ */
173вҶ’export function isAssessComment(body: string): boolean {
174вҶ’  return ALL_MARKERS.some((marker) => body.includes(marker));
175вҶ’}
176вҶ’
177вҶ’/**
178вҶ’ * Check if a comment is a solve command output (legacy format)
179вҶ’ * @deprecated Use isAssessComment instead
180вҶ’ */
181вҶ’export function isSolveComment(body: string): boolean {
182вҶ’  return isAssessComment(body);
183вҶ’}
184вҶ’
185вҶ’/**
186вҶ’ * Find the most recent assess/solve comment from a list of comments
187вҶ’ */
188вҶ’export function findAssessComment(
189вҶ’  comments: IssueComment[],
190вҶ’): IssueComment | null {
191вҶ’  for (let i = comments.length - 1; i >= 0; i--) {
192вҶ’    if (isAssessComment(comments[i].body)) {
193вҶ’      return comments[i];
194вҶ’    }
195вҶ’  }
196вҶ’  return null;
197вҶ’}
198вҶ’
199вҶ’/**
200вҶ’ * Find the most recent solve comment from a list of comments
201вҶ’ * @deprecated Use findAssessComment instead
202вҶ’ */
203вҶ’export function findSolveComment(
204вҶ’  comments: IssueComment[],
205вҶ’): IssueComment | null {
206вҶ’  return findAssessComment(comments);
207вҶ’}
208вҶ’
209вҶ’// в”Җв”Җв”Җ Parsing Functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
210вҶ’
211вҶ’/**
212вҶ’ * Parse phases from a workflow string
213вҶ’ */
214вҶ’function parseWorkflowString(workflowString: string): Phase[] {
215вҶ’  const phases: Phase[] = [];
216вҶ’  const matches = workflowString.matchAll(PHASE_PATTERN);
217вҶ’
218вҶ’  for (const match of matches) {
219вҶ’    const phase = match[1] as Phase;
220вҶ’    if (!phases.includes(phase)) {
221вҶ’      phases.push(phase);
222вҶ’    }
223вҶ’  }
224вҶ’
225вҶ’  return phases;
226вҶ’}
227вҶ’
228вҶ’/**
229вҶ’ * Parse HTML comment markers from a comment body
230вҶ’ *
231вҶ’ * Supports both `assess:` and `solve:` prefixes.
232вҶ’ * When both are present, `assess:` markers take precedence.
233вҶ’ */
234вҶ’export function parseAssessMarkers(body: string): AssessMarkers {
235вҶ’  const markers: AssessMarkers = {};
236вҶ’
237вҶ’  // First pass: collect all markers (both assess: and solve:)
238вҶ’  const allMatches = body.matchAll(HTML_MARKER_PATTERN);
239вҶ’  for (const match of allMatches) {
240вҶ’    applyMarker(markers, match[1], match[2]);
241вҶ’  }
242вҶ’
243вҶ’  // Second pass: assess: markers override solve: markers
244вҶ’  const assessMatches = body.matchAll(ASSESS_HTML_MARKER_PATTERN);
245вҶ’  for (const match of assessMatches) {
246вҶ’    applyMarker(markers, match[1], match[2]);
247вҶ’  }
248вҶ’
249вҶ’  return markers;
250вҶ’}
251вҶ’
252вҶ’/**
253вҶ’ * Apply a single marker key-value pair to the markers object
254вҶ’ */
255вҶ’function applyMarker(markers: AssessMarkers, key: string, value: string): void {
256вҶ’  switch (key) {
257вҶ’    case "phases":
258вҶ’      markers.phases = value.split(",").filter(Boolean);
259вҶ’      break;
260вҶ’    case "skip-spec":
261вҶ’      markers.skipSpec = value === "true";
262вҶ’      break;
263вҶ’    case "browser-test":
264вҶ’      markers.browserTest = value === "true";
265вҶ’      break;
266вҶ’    case "quality-loop":
267вҶ’      markers.qualityLoop = value === "true";
268вҶ’      break;
269вҶ’    case "action":
270вҶ’      if (VALID_ACTIONS.includes(value as AssessAction)) {
271вҶ’        markers.action = value as AssessAction;
272вҶ’      }
273вҶ’      break;
274вҶ’  }
275вҶ’}
276вҶ’
277вҶ’/**
278вҶ’ * Parse HTML comment markers (backward-compatible alias)
279вҶ’ * @deprecated Use parseAssessMarkers instead
280вҶ’ */
281вҶ’export function parseSolveMarkers(body: string): AssessMarkers {
282вҶ’  return parseAssessMarkers(body);
283вҶ’}
284вҶ’
285вҶ’/**
286вҶ’ * Parse an assess/solve comment to extract workflow information
287вҶ’ */
288вҶ’export function parseAssessWorkflow(body: string): AssessWorkflowResult {
289вҶ’  const result: AssessWorkflowResult = {
290вҶ’    phases: [],
291вҶ’    qualityLoop: false,
292вҶ’    issueNumbers: [],
293вҶ’  };
294вҶ’
295вҶ’  // Extract action from "вҶ’ ACTION вҖ” reason" line
296вҶ’  const actionMatch = body.match(
297вҶ’    /вҶ’\s*(PROCEED|CLOSE|MERGE|REWRITE|CLARIFY|PARK)\s*[вҖ”-]/,
298вҶ’  );
299вҶ’  if (actionMatch) {
300вҶ’    result.action = actionMatch[1] as AssessAction;
301вҶ’  }
302вҶ’
303вҶ’  // Extract issue numbers from header (both old and new formats)
304вҶ’  const headerMatch = body.match(
305вҶ’    /## (?:Assess|Solve) (?:Workflow for Issues?|Analysis)(?::\s*|\s+for\s+)([^\n]+)/i,
306вҶ’  );
307вҶ’  if (headerMatch) {
308вҶ’    const numberMatches = headerMatch[1].matchAll(ISSUE_NUMBER_PATTERN);
309вҶ’    for (const match of numberMatches) {
310вҶ’      const num = parseInt(match[1], 10);
311вҶ’      if (!isNaN(num) && !result.issueNumbers.includes(num)) {
312вҶ’        result.issueNumbers.push(num);
313вҶ’      }
314вҶ’    }
315вҶ’  }
316вҶ’
317вҶ’  // Try HTML comment markers first (most reliable, machine-readable)
318вҶ’  const markers = parseAssessMarkers(body);
319вҶ’
320вҶ’  // Action from markers overrides inline detection
321вҶ’  if (markers.action) {
322вҶ’    result.action = markers.action;
323вҶ’  }
324вҶ’
325вҶ’  if (markers.phases && markers.phases.length > 0) {
326вҶ’    result.phases = markers.phases as Phase[];
327вҶ’    result.workflowString = markers.phases.join(" вҶ’ ");
328вҶ’  }
329вҶ’
330вҶ’  if (markers.qualityLoop !== undefined) {
331вҶ’    result.qualityLoop = markers.qualityLoop;
332вҶ’  }
333вҶ’
334вҶ’  // If we got phases from markers, we're done with phase detection
335вҶ’  if (result.phases.length > 0) {
336вҶ’    return result;
337вҶ’  }
338вҶ’
339вҶ’  // Find workflow lines (e.g., "/spec 152" or "spec вҶ’ exec вҶ’ qa")
340вҶ’  const lines = body.split("\n");
341вҶ’
342вҶ’  // First pass: look for arrow notation (most reliable)
343вҶ’  for (const line of lines) {
344вҶ’    if (line.includes("вҶ’") || line.includes("->")) {
345вҶ’      const phases = parseWorkflowString(line);
346вҶ’      if (phases.length > 0) {
347вҶ’        result.phases = phases;
348вҶ’        result.workflowString = line.trim();
349вҶ’        break;
350вҶ’      }
351вҶ’    }
352вҶ’  }
353вҶ’
354вҶ’  // Second pass: if no arrow notation found, collect phases from multiple lines
355вҶ’  if (result.phases.length === 0) {
356вҶ’    const collectedPhases: Phase[] = [];
357вҶ’
358вҶ’    for (const line of lines) {
359вҶ’      if (
360вҶ’        line.includes("/spec") ||
361вҶ’        line.includes("/exec") ||
362вҶ’        line.includes("/test") ||
363вҶ’        line.includes("/qa")
364вҶ’      ) {
365вҶ’        const linePhases = parseWorkflowString(line);
366вҶ’        for (const phase of linePhases) {
367вҶ’          if (!collectedPhases.includes(phase)) {
368вҶ’            collectedPhases.push(phase);
369вҶ’          }
370вҶ’        }
371вҶ’      }
372вҶ’    }
373вҶ’
374вҶ’    if (collectedPhases.length > 0) {
375вҶ’      result.phases = collectedPhases;
376вҶ’      result.workflowString = collectedPhases.map((p) => `/${p}`).join(" вҶ’ ");
377вҶ’    }
378вҶ’  }
379вҶ’
380вҶ’  // If no phases found from lines, try full body
381вҶ’  if (result.phases.length === 0) {
382вҶ’    result.phases = parseWorkflowString(body);
383вҶ’  }
384вҶ’
385вҶ’  // Check for quality loop recommendation (if not already set by markers)
386вҶ’  if (!result.qualityLoop) {
387вҶ’    for (const pattern of QUALITY_LOOP_PATTERNS) {
388вҶ’      if (pattern.test(body)) {
389вҶ’        result.qualityLoop = true;
390вҶ’        break;
391вҶ’      }
392вҶ’    }
393вҶ’  }
394вҶ’
395вҶ’  return result;
396вҶ’}
397вҶ’
398вҶ’/**
399вҶ’ * Parse a solve comment to extract workflow information
400вҶ’ * @deprecated Use parseAssessWorkflow instead
401вҶ’ */
402вҶ’export function parseSolveWorkflow(body: string): AssessWorkflowResult {
403вҶ’  return parseAssessWorkflow(body);
404вҶ’}
405вҶ’
406вҶ’// в”Җв”Җв”Җ Signal Conversion в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
407вҶ’
408вҶ’/**
409вҶ’ * Convert assess workflow result to phase signals
410вҶ’ */
411вҶ’export function assessWorkflowToSignals(
412вҶ’  workflow: AssessWorkflowResult,
413вҶ’): PhaseSignal[] {
414вҶ’  const signals: PhaseSignal[] = [];
415вҶ’
416вҶ’  for (const phase of workflow.phases) {
417вҶ’    signals.push({
418вҶ’      phase,
419вҶ’      source: "assess",
420вҶ’      confidence: "high",
421вҶ’      reason: `Recommended by /assess command: ${workflow.workflowString || phase}`,
422вҶ’    });
423вҶ’  }
424вҶ’
425вҶ’  if (workflow.qualityLoop) {
426вҶ’    signals.push({
427вҶ’      phase: "quality-loop",
428вҶ’      source: "assess",
429вҶ’      confidence: "high",
430вҶ’      reason: "Quality loop recommended by /assess command",
431вҶ’    });
432вҶ’  }
433вҶ’
434вҶ’  return signals;
435вҶ’}
436вҶ’
437вҶ’/**
438вҶ’ * Convert solve workflow result to phase signals
439вҶ’ *
440вҶ’ * Preserves "/solve" wording in reason strings for backward compatibility
441вҶ’ * with existing tests and consumers.
442вҶ’ *
443вҶ’ * @deprecated Use assessWorkflowToSignals instead
444вҶ’ */
445вҶ’export function solveWorkflowToSignals(
446вҶ’  workflow: AssessWorkflowResult,
447вҶ’): PhaseSignal[] {
448вҶ’  const signals: PhaseSignal[] = [];
449вҶ’
450вҶ’  for (const phase of workflow.phases) {
451вҶ’    signals.push({
452вҶ’      phase,
453вҶ’      source: "solve",
454вҶ’      confidence: "high",
455вҶ’      reason: `Recommended by /solve command: ${workflow.workflowString || phase}`,
456вҶ’    });
457вҶ’  }
458вҶ’
459вҶ’  if (workflow.qualityLoop) {
460вҶ’    signals.push({
461вҶ’      phase: "quality-loop",
462вҶ’      source: "solve",
463вҶ’      confidence: "high",
464вҶ’      reason: "Quality loop recommended by /solve command",
465вҶ’    });
466вҶ’  }
467вҶ’
468вҶ’  return signals;
469вҶ’}
