 * Structured data extracted from HTML comment markers
 */
export interface AssessMarkers {
  /** Recommended phases */
  phases?: string[];
  /** Whether browser testing is needed */
  browserTest?: boolean;
  /** Whether quality loop is recommended */
  qualityLoop?: boolean;
  /** The recommended action */
  action?: AssessAction;
}

