 21вҶ’/**
 22вҶ’ * UI-related labels that trigger automatic test phase
 23вҶ’ */
 24вҶ’export const UI_LABELS = ["ui", "frontend", "admin", "web", "browser"];
 25вҶ’
 26вҶ’/**
 27вҶ’ * Bug-related labels that skip spec phase
 28вҶ’ */
 29вҶ’export const BUG_LABELS = ["bug", "fix", "hotfix", "patch"];
 30вҶ’
 31вҶ’/**
 32вҶ’ * Documentation labels that skip spec phase
 33вҶ’ */
 34вҶ’export const DOCS_LABELS = ["docs", "documentation", "readme"];
 35вҶ’
 36вҶ’/**
 37вҶ’ * Complex labels that enable quality loop
 38вҶ’ */
 39вҶ’export const COMPLEX_LABELS = ["complex", "refactor", "breaking", "major"];
 40вҶ’
 41вҶ’/**
 42вҶ’ * Security-related labels that trigger security-review phase
 43вҶ’ */
 44вҶ’export const SECURITY_LABELS = [
 45вҶ’  "security",
 46вҶ’  "auth",
 47вҶ’  "authentication",
 48вҶ’  "permissions",
 49вҶ’  "admin",
 50вҶ’];
 51вҶ’
 52вҶ’/**
 53вҶ’ * Detect phases based on issue labels (like /assess logic)
 54вҶ’ */
 55вҶ’export function detectPhasesFromLabels(labels: string[]): {
 56вҶ’  phases: Phase[];
 57вҶ’  qualityLoop: boolean;
 58вҶ’} {
 59вҶ’  const lowerLabels = labels.map((l) => l.toLowerCase());
 60вҶ’
 61вҶ’  // Check for bug/fix labels вҶ’ exec вҶ’ qa (skip spec)
 62вҶ’  const isBugFix = lowerLabels.some((label) =>
 63вҶ’    BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 64вҶ’  );
 65вҶ’
 66вҶ’  // Check for docs labels вҶ’ exec вҶ’ qa (skip spec)
 67вҶ’  const isDocs = lowerLabels.some((label) =>
 68вҶ’    DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 69вҶ’  );
 70вҶ’
 71вҶ’  // Check for UI labels вҶ’ add test phase
 72вҶ’  const isUI = lowerLabels.some((label) =>
 73вҶ’    UI_LABELS.some((uiLabel) => label.includes(uiLabel)),
 74вҶ’  );
 75вҶ’
 76вҶ’  // Check for complex labels вҶ’ enable quality loop
 77вҶ’  const isComplex = lowerLabels.some((label) =>
 78вҶ’    COMPLEX_LABELS.some((complexLabel) => label.includes(complexLabel)),
 79вҶ’  );
 80вҶ’
 81вҶ’  // Check for security labels вҶ’ add security-review phase
 82вҶ’  const isSecurity = lowerLabels.some((label) =>
 83вҶ’    SECURITY_LABELS.some((secLabel) => label.includes(secLabel)),
 84вҶ’  );
 85вҶ’
 86вҶ’  // Build phase list
 87вҶ’  let phases: Phase[];
 88вҶ’
 89вҶ’  if (isBugFix || isDocs) {
 90вҶ’    // Simple workflow: exec вҶ’ qa
 91вҶ’    phases = ["exec", "qa"];
 92вҶ’  } else if (isUI) {
 93вҶ’    // UI workflow: spec вҶ’ exec вҶ’ test вҶ’ qa
 94вҶ’    phases = ["spec", "exec", "test", "qa"];
 95вҶ’  } else {
 96вҶ’    // Standard workflow: spec вҶ’ exec вҶ’ qa
 97вҶ’    phases = ["spec", "exec", "qa"];
 98вҶ’  }
 99вҶ’
100вҶ’  // Add security-review phase after spec if security labels detected
101вҶ’  if (isSecurity && phases.includes("spec")) {
102вҶ’    const specIndex = phases.indexOf("spec");
103вҶ’    phases.splice(specIndex + 1, 0, "security-review");
104вҶ’  }
105вҶ’
106вҶ’  return { phases, qualityLoop: isComplex };
107вҶ’}
108вҶ’
109вҶ’/**
110вҶ’ * Parse recommended workflow from /spec output
111вҶ’ *
112вҶ’ * Looks for:
113вҶ’ * ## Recommended Workflow
114вҶ’ * **Phases:** exec вҶ’ qa
115вҶ’ * **Quality Loop:** enabled|disabled
116вҶ’ */
117вҶ’export function parseRecommendedWorkflow(output: string): {
118вҶ’  phases: Phase[];
119вҶ’  qualityLoop: boolean;
120вҶ’} | null {
121вҶ’  // Find the Recommended Workflow section
122вҶ’  const workflowMatch = output.match(
123вҶ’    /## Recommended Workflow[\s\S]*?\*\*Phases:\*\*\s*([^\n]+)/i,
124вҶ’  );
125вҶ’
126вҶ’  if (!workflowMatch) {
127вҶ’    return null;
128вҶ’  }
129вҶ’
130вҶ’  // Parse phases from "exec вҶ’ qa" or "spec вҶ’ exec вҶ’ test вҶ’ qa" format
131вҶ’  const phasesStr = workflowMatch[1].trim();
132вҶ’  const phaseNames = phasesStr
133вҶ’    .split(/\s*вҶ’\s*|\s*->\s*|\s*,\s*/)
134вҶ’    .map((p) => p.trim().toLowerCase())
135вҶ’    .filter((p) => p.length > 0);
136вҶ’
137вҶ’  // Validate and convert to Phase type
138вҶ’  const validPhases: Phase[] = [];
139вҶ’  for (const name of phaseNames) {
140вҶ’    if (
141вҶ’      [
142вҶ’        "spec",
143вҶ’        "security-review",
144вҶ’        "testgen",
145вҶ’        "exec",
146вҶ’        "test",
147вҶ’        "qa",
148вҶ’        "loop",
149вҶ’      ].includes(name)
150вҶ’    ) {
151вҶ’      validPhases.push(name as Phase);
152вҶ’    }
153вҶ’  }
154вҶ’
155вҶ’  if (validPhases.length === 0) {
156вҶ’    return null;
157вҶ’  }
158вҶ’
159вҶ’  // Parse quality loop setting
160вҶ’  const qualityLoopMatch = output.match(
161вҶ’    /\*\*Quality Loop:\*\*\s*(enabled|disabled|true|false|yes|no)/i,
162вҶ’  );
163вҶ’  const qualityLoop = qualityLoopMatch
164вҶ’    ? ["enabled", "true", "yes"].includes(qualityLoopMatch[1].toLowerCase())
165вҶ’    : false;
166вҶ’
167вҶ’  return { phases: validPhases, qualityLoop };
168вҶ’}
