170вҶ’/**
171вҶ’ * Check if an issue has UI-related labels
172вҶ’ */
173вҶ’export function hasUILabels(labels: string[]): boolean {
174вҶ’  return labels.some((label) =>
175вҶ’    UI_LABELS.some((uiLabel) => label.toLowerCase().includes(uiLabel)),
176вҶ’  );
177вҶ’}
