179вҶ’/**
180вҶ’ * Determine phases to run based on options and issue labels
181вҶ’ */
182вҶ’export function determinePhasesForIssue(
183вҶ’  basePhases: Phase[],
184вҶ’  labels: string[],
185вҶ’  options: PhaseMapperOptions,
186вҶ’): Phase[] {
187вҶ’  const phases = [...basePhases];
188вҶ’
189вҶ’  // Add testgen phase after spec if requested
190вҶ’  if (options.testgen && phases.includes("spec")) {
191вҶ’    const specIndex = phases.indexOf("spec");
192вҶ’    if (!phases.includes("testgen")) {
193вҶ’      phases.splice(specIndex + 1, 0, "testgen");
194вҶ’    }
195вҶ’  }
196вҶ’
197вҶ’  // Auto-detect UI issues and add test phase
198вҶ’  if (hasUILabels(labels) && !phases.includes("test")) {
199вҶ’    // Add test phase before qa if present, otherwise at the end
200вҶ’    const qaIndex = phases.indexOf("qa");
201вҶ’    if (qaIndex !== -1) {
202вҶ’      phases.splice(qaIndex, 0, "test");
203вҶ’    } else {
204вҶ’      phases.push("test");
205вҶ’    }
206вҶ’  }
207вҶ’
208вҶ’  return phases;
209вҶ’}
