  38вҶ’/**
  39вҶ’ * Emit a structured progress line to stderr for MCP progress notifications.
  40вҶ’ * Only emits when running under an orchestrator (e.g., MCP server).
  41вҶ’ * The MCP handler parses these lines to send `notifications/progress`.
  42вҶ’ *
  43вҶ’ * @param issue - GitHub issue number
  44вҶ’ * @param phase - Phase name (e.g., "spec", "exec", "qa")
  45вҶ’ * @param event - Phase lifecycle event: "start", "complete", or "failed"
  46вҶ’ * @param extra - Optional fields: durationSeconds (on complete), error (on failed)
  47вҶ’ */
  48вҶ’export function emitProgressLine(
  49вҶ’  issue: number,
  50вҶ’  phase: string,
  51вҶ’  event: "start" | "complete" | "failed" = "start",
  52вҶ’  extra?: { durationSeconds?: number; error?: string },
  53вҶ’): void {
  54вҶ’  if (!process.env.SEQUANT_ORCHESTRATOR) return;
  55вҶ’  const payload: Record<string, unknown> = { issue, phase, event };
  56вҶ’  if (extra?.durationSeconds !== undefined) {
  57вҶ’    payload.durationSeconds = extra.durationSeconds;
  58вҶ’  }
  59вҶ’  if (extra?.error !== undefined) {
  60вҶ’    payload.error = extra.error;
  61вҶ’  }
  62вҶ’  const line = `SEQUANT_PROGRESS:${JSON.stringify(payload)}\n`;
  63вҶ’  process.stderr.write(line);
  64вҶ’}
