 310вҶ’/**
 311вҶ’ * Parse environment variables for CI configuration
 312вҶ’ */
 313вҶ’export function getEnvConfig(): Partial<RunOptions> {
 314вҶ’  const config: Partial<RunOptions> = {};
 315вҶ’
 316вҶ’  if (process.env.SEQUANT_QUALITY_LOOP === "true") {
 317вҶ’    config.qualityLoop = true;
 318вҶ’  }
 319вҶ’
 320вҶ’  if (process.env.SEQUANT_MAX_ITERATIONS) {
 321вҶ’    const maxIter = parseInt(process.env.SEQUANT_MAX_ITERATIONS, 10);
 322вҶ’    if (!isNaN(maxIter)) {
 323вҶ’      config.maxIterations = maxIter;
 324вҶ’    }
 325вҶ’  }
 326вҶ’
 327вҶ’  if (process.env.SEQUANT_SMART_TESTS === "false") {
 328вҶ’    config.noSmartTests = true;
 329вҶ’  }
 330вҶ’
 331вҶ’  if (process.env.SEQUANT_TESTGEN === "true") {
 332вҶ’    config.testgen = true;
 333вҶ’  }
 334вҶ’
 335вҶ’  return config;
 336вҶ’}
