 338вҶ’export async function executeBatch(
 339вҶ’  issueNumbers: number[],
 340вҶ’  config: ExecutionConfig,
 341вҶ’  logWriter: LogWriter | null,
 342вҶ’  stateManager: StateManager | null,
 343вҶ’  options: RunOptions,
 344вҶ’  issueInfoMap: Map<number, { title: string; labels: string[] }>,
 345вҶ’  worktreeMap: Map<number, WorktreeInfo>,
 346вҶ’  shutdownManager?: ShutdownManager,
 347вҶ’  packageManager?: string,
 348вҶ’  baseBranch?: string,
 349вҶ’): Promise<IssueResult[]> {
 350вҶ’  const results: IssueResult[] = [];
 351вҶ’
 352вҶ’  for (const issueNumber of issueNumbers) {
 353вҶ’    // Check if shutdown was triggered
 354вҶ’    if (shutdownManager?.shuttingDown) {
 355вҶ’      break;
 356вҶ’    }
 357вҶ’
 358вҶ’    const issueInfo = issueInfoMap.get(issueNumber) ?? {
 359вҶ’      title: `Issue #${issueNumber}`,
 360вҶ’      labels: [],
 361вҶ’    };
 362вҶ’    const worktreeInfo = worktreeMap.get(issueNumber);
 363вҶ’
 364вҶ’    // Start issue logging
 365вҶ’    if (logWriter) {
 366вҶ’      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
 367вҶ’    }
 368вҶ’
 369вҶ’    const result = await runIssueWithLogging(
 370вҶ’      issueNumber,
 371вҶ’      config,
 372вҶ’      logWriter,
 373вҶ’      stateManager,
 374вҶ’      issueInfo.title,
 375вҶ’      issueInfo.labels,
 376вҶ’      options,
 377вҶ’      worktreeInfo?.path,
 378вҶ’      worktreeInfo?.branch,
 379вҶ’      shutdownManager,
 380вҶ’      false, // Batch mode doesn't support chain
 381вҶ’      packageManager,
 382вҶ’      undefined,
 383вҶ’      baseBranch,
 384вҶ’    );
 385вҶ’    results.push(result);
 386вҶ’
 387вҶ’    // Record PR info in log before completing issue
 388вҶ’    if (logWriter && result.prNumber && result.prUrl) {
 389вҶ’      logWriter.setPRInfo(result.prNumber, result.prUrl);
 390вҶ’    }
 391вҶ’
 392вҶ’    // Complete issue logging
 393вҶ’    if (logWriter) {
 394вҶ’      logWriter.completeIssue();
 395вҶ’    }
 396вҶ’  }
 397вҶ’
 398вҶ’  return results;
 399вҶ’}
 400вҶ’
 401вҶ’export async function runIssueWithLogging(
 402вҶ’  issueNumber: number,
 403вҶ’  config: ExecutionConfig,
 404вҶ’  logWriter: LogWriter | null,
 405вҶ’  stateManager: StateManager | null,
 406вҶ’  issueTitle: string,
 407вҶ’  labels: string[],
 408вҶ’  options: RunOptions,
 409вҶ’  worktreePath?: string,
 410вҶ’  branch?: string,
 411вҶ’  shutdownManager?: ShutdownManager,
 412вҶ’  chainMode?: boolean,
 413вҶ’  packageManager?: string,
 414вҶ’  isLastInChain?: boolean,
 415вҶ’  baseBranch?: string,
 416вҶ’): Promise<IssueResult> {
 417вҶ’  const startTime = Date.now();
 418вҶ’  const phaseResults: PhaseResult[] = [];
 419вҶ’  let loopTriggered = false;
 420вҶ’  let sessionId: string | undefined;
 421вҶ’
 422вҶ’  // In parallel mode, suppress per-issue terminal output to prevent interleaving.
 423вҶ’  // The caller (run.ts) handles progress display via updateProgress().
 424вҶ’  const log = config.parallel ? () => {} : console.log.bind(console);
 425вҶ’
 426вҶ’  log(chalk.blue(`\n  Issue #${issueNumber}`));
 427вҶ’  if (worktreePath) {
 428вҶ’    log(chalk.gray(`    Worktree: ${worktreePath}`));
 429вҶ’  }
 430вҶ’
 431вҶ’  // Initialize state tracking for this issue
 432вҶ’  if (stateManager) {
 433вҶ’    try {
 434вҶ’      const existingState = await stateManager.getIssueState(issueNumber);
 435вҶ’      if (!existingState) {
 436вҶ’        await stateManager.initializeIssue(issueNumber, issueTitle, {
 437вҶ’          worktree: worktreePath,
 438вҶ’          branch,
 439вҶ’          qualityLoop: config.qualityLoop,
 440вҶ’          maxIterations: config.maxIterations,
 441вҶ’        });
 442вҶ’      } else {
 443вҶ’        // Update worktree info if it changed
 444вҶ’        if (worktreePath && branch) {
 445вҶ’          await stateManager.updateWorktreeInfo(
 446вҶ’            issueNumber,
 447вҶ’            worktreePath,
 448вҶ’            branch,
 449вҶ’          );
 450вҶ’        }
 451вҶ’      }
 452вҶ’    } catch (error) {
 453вҶ’      // State tracking errors shouldn't stop execution
 454вҶ’      if (config.verbose) {
 455вҶ’        log(chalk.yellow(`    вҡ пёҸ  State tracking error: ${error}`));
 456вҶ’      }
 457вҶ’    }
 458вҶ’  }
 459вҶ’
 460вҶ’  // Determine phases for this specific issue
 461вҶ’  let phases: Phase[];
 462вҶ’  let detectedQualityLoop = false;
 463вҶ’  let specAlreadyRan = false;
 464вҶ’
 465вҶ’  if (options.autoDetectPhases) {
 466вҶ’    // Check if labels indicate a simple bug/fix (skip spec entirely)
 467вҶ’    const lowerLabels = labels.map((l) => l.toLowerCase());
 468вҶ’    const isSimpleBugFix = lowerLabels.some((label) =>
 469вҶ’      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 470вҶ’    );
 471вҶ’
 472вҶ’    // Check if labels indicate documentation-only work (skip spec)
 473вҶ’    const isDocs = lowerLabels.some((label) =>
 474вҶ’      DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 475вҶ’    );
 476вҶ’
 477вҶ’    if (isSimpleBugFix) {
 478вҶ’      // Simple bug fix: skip spec, go straight to exec вҶ’ qa
 479вҶ’      phases = ["exec", "qa"];
 480вҶ’      log(chalk.gray(`    Bug fix detected: ${phases.join(" вҶ’ ")}`));
 481вҶ’    } else if (isDocs) {
 482вҶ’      // Documentation issue: skip spec, lighter pipeline
 483вҶ’      phases = ["exec", "qa"];
 484вҶ’      log(chalk.gray(`    Docs issue detected: ${phases.join(" вҶ’ ")}`));
 485вҶ’    } else {
 486вҶ’      // Run spec first to get recommended workflow
 487вҶ’      log(chalk.gray(`    Running spec to determine workflow...`));
 488вҶ’
 489вҶ’      // Create spinner for spec phase (suppressed in parallel mode to prevent interleaving)
 490вҶ’      const specSpinner = config.parallel
 491вҶ’        ? undefined
 492вҶ’        : new PhaseSpinner({
 493вҶ’            phase: "spec",
 494вҶ’            phaseIndex: 1,
 495вҶ’            totalPhases: 3, // Estimate; will be refined after spec
 496вҶ’            shutdownManager,
 497вҶ’          });
 498вҶ’      specSpinner?.start();
 499вҶ’      emitProgressLine(issueNumber, "spec", "start");
 500вҶ’
 501вҶ’      // Track spec phase start in state
 502вҶ’      if (stateManager) {
 503вҶ’        try {
 504вҶ’          await stateManager.updatePhaseStatus(
 505вҶ’            issueNumber,
 506вҶ’            "spec",
 507вҶ’            "in_progress",
 508вҶ’          );
 509вҶ’        } catch {
 510вҶ’          // State tracking errors shouldn't stop execution
 511вҶ’        }
 512вҶ’      }
 513вҶ’
 514вҶ’      const specStartTime = new Date();
 515вҶ’      // Note: spec runs in main repo (not worktree) for planning
 516вҶ’      const specResult = await executePhaseWithRetry(
 517вҶ’        issueNumber,
 518вҶ’        "spec",
 519вҶ’        config,
 520вҶ’        sessionId,
 521вҶ’        worktreePath, // Will be ignored for spec (non-isolated phase)
 522вҶ’        shutdownManager,
 523вҶ’        specSpinner,
 524вҶ’      );
 525вҶ’      const specEndTime = new Date();
 526вҶ’
 527вҶ’      if (specResult.sessionId) {
 528вҶ’        sessionId = specResult.sessionId;
 529вҶ’        // Update session ID in state for resume capability
 530вҶ’        if (stateManager) {
 531вҶ’          try {
 532вҶ’            await stateManager.updateSessionId(
 533вҶ’              issueNumber,
 534вҶ’              specResult.sessionId,
 535вҶ’            );
 536вҶ’          } catch {
 537вҶ’            // State tracking errors shouldn't stop execution
 538вҶ’          }
 539вҶ’        }
 540вҶ’      }
 541вҶ’
 542вҶ’      phaseResults.push(specResult);
 543вҶ’      specAlreadyRan = true;
 544вҶ’
 545вҶ’      // Emit completion/failure progress event (AC-8)
 546вҶ’      const specDurationSec = Math.round(
 547вҶ’        (specEndTime.getTime() - specStartTime.getTime()) / 1000,
 548вҶ’      );
 549вҶ’      if (specResult.success) {
 550вҶ’        emitProgressLine(issueNumber, "spec", "complete", {
 551вҶ’          durationSeconds: specDurationSec,
 552вҶ’        });
 553вҶ’      } else {
 554вҶ’        emitProgressLine(issueNumber, "spec", "failed", {
 555вҶ’          error: specResult.error ?? "unknown",
 556вҶ’        });
 557вҶ’      }
 558вҶ’
 559вҶ’      // Log spec phase result
 560вҶ’      // Note: Spec runs in main repo, not worktree, so no git diff stats
 561вҶ’      if (logWriter) {
 562вҶ’        // Build errorContext from captured stderr/stdout tails (#447)
 563вҶ’        let specErrorContext: ErrorContext | undefined;
 564вҶ’        if (!specResult.success && specResult.stderrTail) {
 565вҶ’          specErrorContext = {
 566вҶ’            stderrTail: specResult.stderrTail ?? [],
 567вҶ’            stdoutTail: specResult.stdoutTail ?? [],
 568вҶ’            exitCode: specResult.exitCode,
 569вҶ’            category: classifyError(specResult.stderrTail ?? []),
 570вҶ’          };
 571вҶ’        }
 572вҶ’        const phaseLog = createPhaseLogFromTiming(
 573вҶ’          "spec",
 574вҶ’          issueNumber,
 575вҶ’          specStartTime,
 576вҶ’          specEndTime,
 577вҶ’          specResult.success
 578вҶ’            ? "success"
 579вҶ’            : specResult.error?.includes("Timeout")
 580вҶ’              ? "timeout"
 581вҶ’              : "failure",
 582вҶ’          { error: specResult.error, errorContext: specErrorContext },
 583вҶ’        );
 584вҶ’        logWriter.logPhase(phaseLog);
 585вҶ’      }
 586вҶ’
 587вҶ’      // Track spec phase completion in state
 588вҶ’      if (stateManager) {
 589вҶ’        try {
 590вҶ’          const phaseStatus = specResult.success ? "completed" : "failed";
 591вҶ’          await stateManager.updatePhaseStatus(
 592вҶ’            issueNumber,
 593вҶ’            "spec",
 594вҶ’            phaseStatus,
 595вҶ’            {
 596вҶ’              error: specResult.error,
 597вҶ’            },
 598вҶ’          );
 599вҶ’        } catch {
 600вҶ’          // State tracking errors shouldn't stop execution
 601вҶ’        }
 602вҶ’      }
 603вҶ’
 604вҶ’      if (!specResult.success) {
 605вҶ’        specSpinner?.fail(specResult.error);
 606вҶ’        const durationSeconds = (Date.now() - startTime) / 1000;
 607вҶ’        return {
 608вҶ’          issueNumber,
 609вҶ’          success: false,
 610вҶ’          phaseResults,
 611вҶ’          durationSeconds,
 612вҶ’          loopTriggered: false,
 613вҶ’        };
 614вҶ’      }
 615вҶ’
 616вҶ’      specSpinner?.succeed();
 617вҶ’
 618вҶ’      // Parse recommended workflow from spec output
 619вҶ’      const parsedWorkflow = specResult.output
 620вҶ’        ? parseRecommendedWorkflow(specResult.output)
 621вҶ’        : null;
 622вҶ’
 623вҶ’      if (parsedWorkflow) {
 624вҶ’        // Remove spec from phases since we already ran it
 625вҶ’        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
 626вҶ’        detectedQualityLoop = parsedWorkflow.qualityLoop;
 627вҶ’        log(
 628вҶ’          chalk.gray(
 629вҶ’            `    Spec recommends: ${phases.join(" вҶ’ ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
 630вҶ’          ),
 631вҶ’        );
 632вҶ’      } else {
 633вҶ’        // Fall back to label-based detection
 634вҶ’        log(
 635вҶ’          chalk.yellow(
 636вҶ’            `    Could not parse spec recommendation, using label-based detection`,
 637вҶ’          ),
 638вҶ’        );
 639вҶ’        const detected = detectPhasesFromLabels(labels);
 640вҶ’        phases = detected.phases.filter((p) => p !== "spec");
 641вҶ’        detectedQualityLoop = detected.qualityLoop;
 642вҶ’        log(chalk.gray(`    Fallback: ${phases.join(" вҶ’ ")}`));
 643вҶ’      }
 644вҶ’    }
 645вҶ’  } else {
 646вҶ’    // Use explicit phases with adjustments
 647вҶ’    phases = determinePhasesForIssue(config.phases, labels, options);
 648вҶ’    if (phases.length !== config.phases.length) {
 649вҶ’      log(chalk.gray(`    Phases adjusted: ${phases.join(" вҶ’ ")}`));
 650вҶ’    }
 651вҶ’  }
 652вҶ’
 653вҶ’  // Resume: filter out completed phases if --resume flag is set
 654вҶ’  if (options.resume) {
 655вҶ’    const resumeResult = filterResumedPhases(issueNumber, phases, true);
 656вҶ’    if (resumeResult.skipped.length > 0) {
 657вҶ’      log(
 658вҶ’        chalk.gray(
 659вҶ’          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
 660вҶ’        ),
 661вҶ’      );
 662вҶ’      phases = resumeResult.phases;
 663вҶ’    }
 664вҶ’    // Also skip spec if it was auto-detected as completed
 665вҶ’    if (
 666вҶ’      specAlreadyRan &&
 667вҶ’      resumeResult.skipped.length === 0 &&
 668вҶ’      resumeResult.phases.length === 0
 669вҶ’    ) {
 670вҶ’      log(chalk.gray(`    Resume: all phases already completed`));
 671вҶ’    }
 672вҶ’  }
 673вҶ’
 674вҶ’  // Add testgen phase if requested (and spec was in the phases)
 675вҶ’  if (
 676вҶ’    options.testgen &&
 677вҶ’    (phases.includes("spec") || specAlreadyRan) &&
 678вҶ’    !phases.includes("testgen")
 679вҶ’  ) {
 680вҶ’    // Insert testgen at the beginning if spec already ran, otherwise after spec
 681вҶ’    if (specAlreadyRan) {
 682вҶ’      phases.unshift("testgen");
 683вҶ’    } else {
 684вҶ’      const specIndex = phases.indexOf("spec");
 685вҶ’      if (specIndex !== -1) {
 686вҶ’        phases.splice(specIndex + 1, 0, "testgen");
 687вҶ’      }
 688вҶ’    }
 689вҶ’  }
 690вҶ’
 691вҶ’  // Build per-issue config with issue type metadata for skill env propagation
 692вҶ’  const lowerLabelsForType = labels.map((l) => l.toLowerCase());
 693вҶ’  const issueIsDocs = lowerLabelsForType.some((label) =>
 694вҶ’    DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 695вҶ’  );
 696вҶ’  const issueConfig: ExecutionConfig = issueIsDocs
 697вҶ’    ? { ...config, issueType: "docs" }
 698вҶ’    : config;
 699вҶ’
 700вҶ’  let iteration = 0;
 701вҶ’  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
 702вҶ’  const maxIterations = useQualityLoop ? config.maxIterations : 1;
 703вҶ’  let completedSuccessfully = false;
 704вҶ’
 705вҶ’  while (iteration < maxIterations) {
 706вҶ’    iteration++;
 707вҶ’
 708вҶ’    if (useQualityLoop && iteration > 1) {
 709вҶ’      log(
 710вҶ’        chalk.yellow(
 711вҶ’          `    Quality loop iteration ${iteration}/${maxIterations}`,
 712вҶ’        ),
 713вҶ’      );
 714вҶ’      loopTriggered = true;
 715вҶ’    }
 716вҶ’
 717вҶ’    let phasesFailed = false;
 718вҶ’
 719вҶ’    // Calculate total phases for progress indicator
 720вҶ’    // If spec already ran in auto-detect mode, it's counted separately
 721вҶ’    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
 722вҶ’    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
 723вҶ’
 724вҶ’    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
 725вҶ’      const phase = phases[phaseIdx];
 726вҶ’      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
 727вҶ’
 728вҶ’      // Create spinner for this phase (suppressed in parallel mode)
 729вҶ’      const phaseSpinner = config.parallel
 730вҶ’        ? undefined
 731вҶ’        : new PhaseSpinner({
 732вҶ’            phase,
 733вҶ’            phaseIndex: phaseNumber,
 734вҶ’            totalPhases,
 735вҶ’            shutdownManager,
 736вҶ’            iteration: useQualityLoop ? iteration : undefined,
 737вҶ’          });
 738вҶ’      phaseSpinner?.start();
 739вҶ’      emitProgressLine(issueNumber, phase, "start");
 740вҶ’
 741вҶ’      // Track phase start in state
 742вҶ’      if (stateManager) {
 743вҶ’        try {
 744вҶ’          await stateManager.updatePhaseStatus(
 745вҶ’            issueNumber,
 746вҶ’            phase as Phase,
 747вҶ’            "in_progress",
 748вҶ’          );
 749вҶ’        } catch {
 750вҶ’          // State tracking errors shouldn't stop execution
 751вҶ’        }
 752вҶ’      }
 753вҶ’
 754вҶ’      const phaseStartTime = new Date();
 755вҶ’      const result = await executePhaseWithRetry(
 756вҶ’        issueNumber,
 757вҶ’        phase,
 758вҶ’        issueConfig,
 759вҶ’        sessionId,
 760вҶ’        worktreePath,
 761вҶ’        shutdownManager,
 762вҶ’        phaseSpinner,
 763вҶ’      );
 764вҶ’      const phaseEndTime = new Date();
 765вҶ’
 766вҶ’      // Capture session ID for subsequent phases
 767вҶ’      if (result.sessionId) {
 768вҶ’        sessionId = result.sessionId;
 769вҶ’        // Update session ID in state for resume capability
 770вҶ’        if (stateManager) {
 771вҶ’          try {
 772вҶ’            await stateManager.updateSessionId(issueNumber, result.sessionId);
 773вҶ’          } catch {
 774вҶ’            // State tracking errors shouldn't stop execution
 775вҶ’          }
 776вҶ’        }
 777вҶ’      }
 778вҶ’
 779вҶ’      phaseResults.push(result);
 780вҶ’
 781вҶ’      // Emit completion/failure progress event (AC-8)
 782вҶ’      const phaseDurationSec = Math.round(
 783вҶ’        (phaseEndTime.getTime() - phaseStartTime.getTime()) / 1000,
 784вҶ’      );
 785вҶ’      if (result.success) {
 786вҶ’        emitProgressLine(issueNumber, phase, "complete", {
 787вҶ’          durationSeconds: phaseDurationSec,
 788вҶ’        });
 789вҶ’      } else {
 790вҶ’        emitProgressLine(issueNumber, phase, "failed", {
 791вҶ’          error: result.error ?? "unknown",
 792вҶ’        });
 793вҶ’      }
 794вҶ’
