102вҶ’ * Also matches without slash: `spec`, `exec`, `test`, `qa` (for arrow notation)
103вҶ’ */
104вҶ’const PHASE_PATTERN =
105вҶ’  /\/?(?<!\w)(spec|exec|test|qa|security-review|testgen|loop)(?!\w)/g;
106вҶ’
107вҶ’/**
108вҶ’ * Pattern to detect quality loop recommendation
109вҶ’ */
110вҶ’const QUALITY_LOOP_PATTERNS = [
111вҶ’  /quality\s*loop.*auto-enable/i,
112вҶ’  /--quality-loop/i,
113вҶ’  /quality\s*loop.*recommended/i,
114вҶ’  /enable.*quality\s*loop/i,
115вҶ’];
116вҶ’
117вҶ’/**
118вҶ’ * Pattern to extract structured data from HTML comment markers
119вҶ’ * Matches both: <!-- assess:phases=exec,qa --> and <!-- solve:phases=exec,qa -->
120вҶ’ */
121вҶ’const HTML_MARKER_PATTERN =
122вҶ’  /<!--\s*(?:assess|solve):(\w[\w-]*)=([\w,.-]*)\s*-->/g;
123вҶ’
124вҶ’/**
125вҶ’ * Pattern to extract assess-specific HTML markers (takes precedence)
126вҶ’ */
127вҶ’const ASSESS_HTML_MARKER_PATTERN = /<!--\s*assess:(\w[\w-]*)=([\w,.-]*)\s*-->/g;
128вҶ’
129вҶ’/**
130вҶ’ * Pattern to extract issue numbers from header
131вҶ’ * Matches: "## Solve Workflow for Issues: 123, 456" or "#123"
132вҶ’ */
133вҶ’const ISSUE_NUMBER_PATTERN = /#?(\d+)/g;
134вҶ’
135вҶ’/**
136вҶ’ * Valid assess actions
137вҶ’ */
138вҶ’const VALID_ACTIONS: AssessAction[] = [
139вҶ’  "PROCEED",
140вҶ’  "CLOSE",
141вҶ’  "MERGE",
142вҶ’  "REWRITE",
143вҶ’  "CLARIFY",
144вҶ’  "PARK",
145вҶ’];
146вҶ’
147вҶ’/**
148вҶ’ * Structured data extracted from HTML comment markers
149вҶ’ */
150вҶ’export interface AssessMarkers {
151вҶ’  /** Recommended phases */
152вҶ’  phases?: string[];
153вҶ’  /** Whether browser testing is needed */
154вҶ’  browserTest?: boolean;
155вҶ’  /** Whether quality loop is recommended */
156вҶ’  qualityLoop?: boolean;
157вҶ’  /** The recommended action */
158вҶ’  action?: AssessAction;
159вҶ’}
