209вҶ’/**
210вҶ’ * Parse phases from a workflow string
211вҶ’ */
212вҶ’function parseWorkflowString(workflowString: string): Phase[] {
213вҶ’  const phases: Phase[] = [];
214вҶ’  const matches = workflowString.matchAll(PHASE_PATTERN);
215вҶ’
216вҶ’  for (const match of matches) {
217вҶ’    const phase = match[1] as Phase;
218вҶ’    if (!phases.includes(phase)) {
219вҶ’      phases.push(phase);
220вҶ’    }
221вҶ’  }
222вҶ’
223вҶ’  return phases;
224вҶ’}
225вҶ’
226вҶ’/**
227вҶ’ * Parse HTML comment markers from a comment body
228вҶ’ *
229вҶ’ * Supports both `assess:` and `solve:` prefixes.
230вҶ’ * When both are present, `assess:` markers take precedence.
231вҶ’ */
232вҶ’export function parseAssessMarkers(body: string): AssessMarkers {
233вҶ’  const markers: AssessMarkers = {};
234вҶ’
235вҶ’  // First pass: collect all markers (both assess: and solve:)
236вҶ’  const allMatches = body.matchAll(HTML_MARKER_PATTERN);
237вҶ’  for (const match of allMatches) {
238вҶ’    applyMarker(markers, match[1], match[2]);
239вҶ’  }
240вҶ’
241вҶ’  // Second pass: assess: markers override solve: markers
242вҶ’  const assessMatches = body.matchAll(ASSESS_HTML_MARKER_PATTERN);
243вҶ’  for (const match of assessMatches) {
244вҶ’    applyMarker(markers, match[1], match[2]);
245вҶ’  }
246вҶ’
247вҶ’  return markers;
248вҶ’}
249вҶ’
250вҶ’/**
251вҶ’ * Apply a single marker key-value pair to the markers object
252вҶ’ */
253вҶ’function applyMarker(markers: AssessMarkers, key: string, value: string): void {
254вҶ’  switch (key) {
255вҶ’    case "phases":
256вҶ’      markers.phases = value.split(",").filter(Boolean);
257вҶ’      break;
258вҶ’    case "browser-test":
259вҶ’      markers.browserTest = value === "true";
260вҶ’      break;
261вҶ’    case "quality-loop":
262вҶ’      markers.qualityLoop = value === "true";
263вҶ’      break;
264вҶ’    case "action":
265вҶ’      if (VALID_ACTIONS.includes(value as AssessAction)) {
266вҶ’        markers.action = value as AssessAction;
267вҶ’      }
268вҶ’      break;
269вҶ’  }
270вҶ’}
271вҶ’
272вҶ’/**
273вҶ’ * Parse HTML comment markers (backward-compatible alias)
274вҶ’ * @deprecated Use parseAssessMarkers instead
275вҶ’ */
276вҶ’export function parseSolveMarkers(body: string): AssessMarkers {
277вҶ’  return parseAssessMarkers(body);
278вҶ’}
