280вҶ’/**
281вҶ’ * Parse an assess/solve comment to extract workflow information
282вҶ’ */
283вҶ’export function parseAssessWorkflow(body: string): AssessWorkflowResult {
284вҶ’  const result: AssessWorkflowResult = {
285вҶ’    phases: [],
286вҶ’    qualityLoop: false,
287вҶ’    issueNumbers: [],
288вҶ’  };
289вҶ’
290вҶ’  // Extract action from "вҶ’ ACTION вҖ” reason" line
291вҶ’  const actionMatch = body.match(
292вҶ’    /вҶ’\s*(PROCEED|CLOSE|MERGE|REWRITE|CLARIFY|PARK)\s*[вҖ”-]/,
293вҶ’  );
294вҶ’  if (actionMatch) {
295вҶ’    result.action = actionMatch[1] as AssessAction;
296вҶ’  }
297вҶ’
298вҶ’  // Extract issue numbers from header (both old and new formats)
299вҶ’  const headerMatch = body.match(
300вҶ’    /## (?:Assess|Solve) (?:Workflow for Issues?|Analysis)(?::\s*|\s+for\s+)([^\n]+)/i,
301вҶ’  );
302вҶ’  if (headerMatch) {
303вҶ’    const numberMatches = headerMatch[1].matchAll(ISSUE_NUMBER_PATTERN);
304вҶ’    for (const match of numberMatches) {
305вҶ’      const num = parseInt(match[1], 10);
306вҶ’      if (!isNaN(num) && !result.issueNumbers.includes(num)) {
307вҶ’        result.issueNumbers.push(num);
308вҶ’      }
309вҶ’    }
310вҶ’  }
311вҶ’
312вҶ’  // Try HTML comment markers first (most reliable, machine-readable)
313вҶ’  const markers = parseAssessMarkers(body);
314вҶ’
315вҶ’  // Action from markers overrides inline detection
316вҶ’  if (markers.action) {
317вҶ’    result.action = markers.action;
318вҶ’  }
319вҶ’
320вҶ’  if (markers.phases && markers.phases.length > 0) {
321вҶ’    result.phases = markers.phases as Phase[];
322вҶ’    result.workflowString = markers.phases.join(" вҶ’ ");
323вҶ’  }
324вҶ’
325вҶ’  if (markers.qualityLoop !== undefined) {
326вҶ’    result.qualityLoop = markers.qualityLoop;
327вҶ’  }
328вҶ’
329вҶ’  // If we got phases from markers, we're done with phase detection
330вҶ’  if (result.phases.length > 0) {
331вҶ’    return result;
332вҶ’  }
333вҶ’
334вҶ’  // Find workflow lines (e.g., "/spec 152" or "spec вҶ’ exec вҶ’ qa")
335вҶ’  const lines = body.split("\n");
336вҶ’
337вҶ’  // First pass: look for arrow notation (most reliable)
338вҶ’  for (const line of lines) {
339вҶ’    if (line.includes("вҶ’") || line.includes("->")) {
340вҶ’      const phases = parseWorkflowString(line);
341вҶ’      if (phases.length > 0) {
342вҶ’        result.phases = phases;
343вҶ’        result.workflowString = line.trim();
344вҶ’        break;
345вҶ’      }
346вҶ’    }
347вҶ’  }
348вҶ’
349вҶ’  // Second pass: if no arrow notation found, collect phases from multiple lines
350вҶ’  if (result.phases.length === 0) {
351вҶ’    const collectedPhases: Phase[] = [];
352вҶ’
353вҶ’    for (const line of lines) {
354вҶ’      if (
355вҶ’        line.includes("/spec") ||
356вҶ’        line.includes("/exec") ||
357вҶ’        line.includes("/test") ||
358вҶ’        line.includes("/qa")
359вҶ’      ) {
360вҶ’        const linePhases = parseWorkflowString(line);
361вҶ’        for (const phase of linePhases) {
362вҶ’          if (!collectedPhases.includes(phase)) {
363вҶ’            collectedPhases.push(phase);
364вҶ’          }
365вҶ’        }
366вҶ’      }
367вҶ’    }
368вҶ’
369вҶ’    if (collectedPhases.length > 0) {
370вҶ’      result.phases = collectedPhases;
371вҶ’      result.workflowString = collectedPhases.map((p) => `/${p}`).join(" вҶ’ ");
372вҶ’    }
373вҶ’  }
374вҶ’
375вҶ’  // If no phases found from lines, try full body
376вҶ’  if (result.phases.length === 0) {
377вҶ’    result.phases = parseWorkflowString(body);
378вҶ’  }
379вҶ’
380вҶ’  // Check for quality loop recommendation (if not already set by markers)
381вҶ’  if (!result.qualityLoop) {
382вҶ’    for (const pattern of QUALITY_LOOP_PATTERNS) {
383вҶ’      if (pattern.test(body)) {
384вҶ’        result.qualityLoop = true;
385вҶ’        break;
386вҶ’      }
387вҶ’    }
388вҶ’  }
389вҶ’
390вҶ’  return result;
391вҶ’}
