 156вҶ’  try {
 157вҶ’    const result = spawnSync(
 158вҶ’      "gh",
 159вҶ’      ["issue", "view", String(issueNumber), "--json", "title,labels"],
 160вҶ’      { stdio: "pipe" },
 161вҶ’    );
 162вҶ’
 163вҶ’    if (result.status === 0) {
 164вҶ’      const data = JSON.parse(result.stdout.toString());
 165вҶ’      return {
 166вҶ’        title: data.title || `Issue #${issueNumber}`,
 167вҶ’        labels: Array.isArray(data.labels)
 168вҶ’          ? data.labels.map((l: { name: string }) => l.name)
 169вҶ’          : [],
 170вҶ’      };
 171вҶ’    }
 172вҶ’  } catch {
 173вҶ’    // Ignore errors, use defaults
 174вҶ’  }
 175вҶ’
 176вҶ’  return { title: `Issue #${issueNumber}`, labels: [] };
