 179вҶ’/**
 180вҶ’ * Parse dependencies from issue body and labels
 181вҶ’ * Returns array of issue numbers this issue depends on
 182вҶ’ */
 183вҶ’export function parseDependencies(issueNumber: number): number[] {
 184вҶ’  try {
 185вҶ’    const result = spawnSync(
 186вҶ’      "gh",
 187вҶ’      ["issue", "view", String(issueNumber), "--json", "body,labels"],
 188вҶ’      { stdio: "pipe" },
 189вҶ’    );
 190вҶ’
 191вҶ’    if (result.status !== 0) return [];
 192вҶ’
 193вҶ’    const data = JSON.parse(result.stdout.toString());
 194вҶ’    const dependencies: number[] = [];
 195вҶ’
 196вҶ’    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
 197вҶ’    if (data.body) {
 198вҶ’      const bodyMatch = data.body.match(
 199вҶ’        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
 200вҶ’      );
 201вҶ’      if (bodyMatch) {
 202вҶ’        for (const match of bodyMatch) {
 203вҶ’          const numMatch = match.match(/(\d+)/);
 204вҶ’          if (numMatch) {
 205вҶ’            dependencies.push(parseInt(numMatch[1], 10));
 206вҶ’          }
 207вҶ’        }
 208вҶ’      }
 209вҶ’    }
 210вҶ’
 211вҶ’    // Parse from labels: "depends-on/123" or "depends-on-123"
 212вҶ’    if (data.labels && Array.isArray(data.labels)) {
 213вҶ’      for (const label of data.labels) {
 214вҶ’        const labelName = label.name || label;
 215вҶ’        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
 216вҶ’        if (labelMatch) {
 217вҶ’          dependencies.push(parseInt(labelMatch[1], 10));
 218вҶ’        }
 219вҶ’      }
 220вҶ’    }
 221вҶ’
 222вҶ’    return [...new Set(dependencies)]; // Remove duplicates
 223вҶ’  } catch {
 224вҶ’    return [];
 225вҶ’  }
 226вҶ’}
