 228вҶ’/**
 229вҶ’ * Sort issues by dependencies (topological sort)
 230вҶ’ * Issues with no dependencies come first, then issues that depend on them
 231вҶ’ */
 232вҶ’export function sortByDependencies(issueNumbers: number[]): number[] {
 233вҶ’  // Build dependency graph
 234вҶ’  const dependsOn = new Map<number, number[]>();
 235вҶ’  for (const issue of issueNumbers) {
 236вҶ’    const deps = parseDependencies(issue);
 237вҶ’    // Only include dependencies that are in our issue list
 238вҶ’    dependsOn.set(
 239вҶ’      issue,
 240вҶ’      deps.filter((d) => issueNumbers.includes(d)),
 241вҶ’    );
 242вҶ’  }
 243вҶ’
 244вҶ’  // Topological sort using Kahn's algorithm
 245вҶ’  const inDegree = new Map<number, number>();
 246вҶ’  for (const issue of issueNumbers) {
 247вҶ’    inDegree.set(issue, 0);
 248вҶ’  }
 249вҶ’  for (const deps of dependsOn.values()) {
 250вҶ’    for (const dep of deps) {
 251вҶ’      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
 252вҶ’    }
 253вҶ’  }
 254вҶ’
 255вҶ’  // Note: inDegree counts how many issues depend on each issue
 256вҶ’  // We want to process issues that have no dependencies first,
 257вҶ’  // so dependent issues come after their prerequisites
 258вҶ’  const sorted: number[] = [];
 259вҶ’  const queue: number[] = [];
 260вҶ’
 261вҶ’  // Start with issues that have no dependencies
 262вҶ’  for (const issue of issueNumbers) {
 263вҶ’    const deps = dependsOn.get(issue) || [];
 264вҶ’    if (deps.length === 0) {
 265вҶ’      queue.push(issue);
 266вҶ’    }
 267вҶ’  }
 268вҶ’
 269вҶ’  const visited = new Set<number>();
 270вҶ’  while (queue.length > 0) {
 271вҶ’    const issue = queue.shift()!;
 272вҶ’    if (visited.has(issue)) continue;
 273вҶ’    visited.add(issue);
 274вҶ’    sorted.push(issue);
 275вҶ’
 276вҶ’    // Find issues that depend on this one
 277вҶ’    for (const [other, deps] of dependsOn.entries()) {
 278вҶ’      if (deps.includes(issue) && !visited.has(other)) {
 279вҶ’        // Check if all dependencies of 'other' are satisfied
 280вҶ’        const allDepsSatisfied = deps.every((d) => visited.has(d));
 281вҶ’        if (allDepsSatisfied) {
 282вҶ’          queue.push(other);
 283вҶ’        }
 284вҶ’      }
 285вҶ’    }
 286вҶ’  }
 287вҶ’
 288вҶ’  // Add any remaining issues (circular dependencies or unvisited)
 289вҶ’  for (const issue of issueNumbers) {
 290вҶ’    if (!visited.has(issue)) {
 291вҶ’      sorted.push(issue);
 292вҶ’    }
 293вҶ’  }
 294вҶ’
 295вҶ’  return sorted;
 296вҶ’}
