 338вҶ’export async function executeBatch(
 339вҶ’  issueNumbers: number[],
 340вҶ’  config: ExecutionConfig,
 341вҶ’  logWriter: LogWriter | null,
 342вҶ’  stateManager: StateManager | null,
 343вҶ’  options: RunOptions,
 344вҶ’  issueInfoMap: Map<number, { title: string; labels: string[] }>,
 345вҶ’  worktreeMap: Map<number, WorktreeInfo>,
 346вҶ’  shutdownManager?: ShutdownManager,
 347вҶ’  packageManager?: string,
 348вҶ’  baseBranch?: string,
 349вҶ’): Promise<IssueResult[]> {
 350вҶ’  const results: IssueResult[] = [];
 351вҶ’
 352вҶ’  for (const issueNumber of issueNumbers) {
 353вҶ’    // Check if shutdown was triggered
 354вҶ’    if (shutdownManager?.shuttingDown) {
 355вҶ’      break;
 356вҶ’    }
 357вҶ’
 358вҶ’    const issueInfo = issueInfoMap.get(issueNumber) ?? {
 359вҶ’      title: `Issue #${issueNumber}`,
 360вҶ’      labels: [],
 361вҶ’    };
 362вҶ’    const worktreeInfo = worktreeMap.get(issueNumber);
 363вҶ’
 364вҶ’    // Start issue logging
 365вҶ’    if (logWriter) {
 366вҶ’      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
 367вҶ’    }
 368вҶ’
 369вҶ’    const result = await runIssueWithLogging(
 370вҶ’      issueNumber,
 371вҶ’      config,
 372вҶ’      logWriter,
 373вҶ’      stateManager,
 374вҶ’      issueInfo.title,
 375вҶ’      issueInfo.labels,
 376вҶ’      options,
 377вҶ’      worktreeInfo?.path,
 378вҶ’      worktreeInfo?.branch,
 379вҶ’      shutdownManager,
 380вҶ’      false, // Batch mode doesn't support chain
 381вҶ’      packageManager,
 382вҶ’      undefined,
 383вҶ’      baseBranch,
 384вҶ’    );
 385вҶ’    results.push(result);
 386вҶ’
 387вҶ’    // Record PR info in log before completing issue
 388вҶ’    if (logWriter && result.prNumber && result.prUrl) {
 389вҶ’      logWriter.setPRInfo(result.prNumber, result.prUrl);
 390вҶ’    }
 391вҶ’
 392вҶ’    // Complete issue logging
 393вҶ’    if (logWriter) {
 394вҶ’      logWriter.completeIssue();
 395вҶ’    }
 396вҶ’  }
 397вҶ’
 398вҶ’  return results;
 399вҶ’}
