 401вҶ’export async function runIssueWithLogging(
 402вҶ’  issueNumber: number,
 403вҶ’  config: ExecutionConfig,
 404вҶ’  logWriter: LogWriter | null,
 405вҶ’  stateManager: StateManager | null,
 406вҶ’  issueTitle: string,
 407вҶ’  labels: string[],
 408вҶ’  options: RunOptions,
 409вҶ’  worktreePath?: string,
 410вҶ’  branch?: string,
 411вҶ’  shutdownManager?: ShutdownManager,
 412вҶ’  chainMode?: boolean,
 413вҶ’  packageManager?: string,
 414вҶ’  isLastInChain?: boolean,
 415вҶ’  baseBranch?: string,
 416вҶ’): Promise<IssueResult> {
 417вҶ’  const startTime = Date.now();
 418вҶ’  const phaseResults: PhaseResult[] = [];
 419вҶ’  let loopTriggered = false;
 420вҶ’  let sessionId: string | undefined;
 421вҶ’
 422вҶ’  // In parallel mode, suppress per-issue terminal output to prevent interleaving.
 423вҶ’  // The caller (run.ts) handles progress display via updateProgress().
 424вҶ’  const log = config.parallel ? () => {} : console.log.bind(console);
 425вҶ’
 426вҶ’  log(chalk.blue(`\n  Issue #${issueNumber}`));
 427вҶ’  if (worktreePath) {
 428вҶ’    log(chalk.gray(`    Worktree: ${worktreePath}`));
 429вҶ’  }
 430вҶ’
 431вҶ’  // Initialize state tracking for this issue
 432вҶ’  if (stateManager) {
 433вҶ’    try {
 434вҶ’      const existingState = await stateManager.getIssueState(issueNumber);
 435вҶ’      if (!existingState) {
 436вҶ’        await stateManager.initializeIssue(issueNumber, issueTitle, {
 437вҶ’          worktree: worktreePath,
 438вҶ’          branch,
 439вҶ’          qualityLoop: config.qualityLoop,
 440вҶ’          maxIterations: config.maxIterations,
 441вҶ’        });
 442вҶ’      } else {
 443вҶ’        // Update worktree info if it changed
 444вҶ’        if (worktreePath && branch) {
 445вҶ’          await stateManager.updateWorktreeInfo(
 446вҶ’            issueNumber,
 447вҶ’            worktreePath,
 448вҶ’            branch,
 449вҶ’          );
 450вҶ’        }
 451вҶ’      }
 452вҶ’    } catch (error) {
 453вҶ’      // State tracking errors shouldn't stop execution
 454вҶ’      if (config.verbose) {
 455вҶ’        log(chalk.yellow(`    вҡ пёҸ  State tracking error: ${error}`));
 456вҶ’      }
 457вҶ’    }
 458вҶ’  }
 459вҶ’
 460вҶ’  // Determine phases for this specific issue
 461вҶ’  let phases: Phase[];
 462вҶ’  let detectedQualityLoop = false;
 463вҶ’  let specAlreadyRan = false;
 464вҶ’
 465вҶ’  if (options.autoDetectPhases) {
 466вҶ’    // Check if labels indicate a simple bug/fix (skip spec entirely)
 467вҶ’    const lowerLabels = labels.map((l) => l.toLowerCase());
 468вҶ’    const isSimpleBugFix = lowerLabels.some((label) =>
 469вҶ’      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 470вҶ’    );
 471вҶ’
 472вҶ’    // Check if labels indicate documentation-only work (skip spec)
 473вҶ’    const isDocs = lowerLabels.some((label) =>
 474вҶ’      DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 475вҶ’    );
 476вҶ’
 477вҶ’    if (isSimpleBugFix) {
 478вҶ’      // Simple bug fix: skip spec, go straight to exec вҶ’ qa
 479вҶ’      phases = ["exec", "qa"];
 480вҶ’      log(chalk.gray(`    Bug fix detected: ${phases.join(" вҶ’ ")}`));
 481вҶ’    } else if (isDocs) {
 482вҶ’      // Documentation issue: skip spec, lighter pipeline
 483вҶ’      phases = ["exec", "qa"];
 484вҶ’      log(chalk.gray(`    Docs issue detected: ${phases.join(" вҶ’ ")}`));
 485вҶ’    } else {
 486вҶ’      // Run spec first to get recommended workflow
 487вҶ’      log(chalk.gray(`    Running spec to determine workflow...`));
 488вҶ’
 489вҶ’      // Create spinner for spec phase (suppressed in parallel mode to prevent interleaving)
 490вҶ’      const specSpinner = config.parallel
 491вҶ’        ? undefined
 492вҶ’        : new PhaseSpinner({
 493вҶ’            phase: "spec",
 494вҶ’            phaseIndex: 1,
 495вҶ’            totalPhases: 3, // Estimate; will be refined after spec
 496вҶ’            shutdownManager,
 497вҶ’          });
 498вҶ’      specSpinner?.start();
 499вҶ’      emitProgressLine(issueNumber, "spec", "start");
 500вҶ’
 501вҶ’      // Track spec phase start in state
 502вҶ’      if (stateManager) {
 503вҶ’        try {
 504вҶ’          await stateManager.updatePhaseStatus(
 505вҶ’            issueNumber,
 506вҶ’            "spec",
 507вҶ’            "in_progress",
 508вҶ’          );
 509вҶ’        } catch {
 510вҶ’          // State tracking errors shouldn't stop execution
 511вҶ’        }
 512вҶ’      }
 513вҶ’
 514вҶ’      const specStartTime = new Date();
 515вҶ’      // Note: spec runs in main repo (not worktree) for planning
 516вҶ’      const specResult = await executePhaseWithRetry(
 517вҶ’        issueNumber,
 518вҶ’        "spec",
 519вҶ’        config,
 520вҶ’        sessionId,
 521вҶ’        worktreePath, // Will be ignored for spec (non-isolated phase)
 522вҶ’        shutdownManager,
 523вҶ’        specSpinner,
 524вҶ’      );
 525вҶ’      const specEndTime = new Date();
 526вҶ’
 527вҶ’      if (specResult.sessionId) {
