    signals.push({
      phase,
      source: "solve",
      confidence: "high",
      reason: `Recommended by /solve command: ${workflow.workflowString || phase}`,
    });
  }

  if (workflow.qualityLoop) {
    signals.push({
      phase: "quality-loop",
      source: "solve",
      confidence: "high",
      reason: "Quality loop recommended by /solve command",
    });
  }

  return signals;
}

